const table=layui.table,util=layui.util;table.render({elem:"#tags",height:500,url:"/api/tag/list",page:!0,cols:[[{field:"tagId",title:"ID",width:100},{field:"content",title:"内容"},{title:"使用次数",templet:({articles:articles})=>articles.length},{title:"创建者",templet:({user:user})=>user.nickName},{title:"创建时间",templet:({createdAt:createdAt})=>util.toDateString(createdAt,"yyyy-MM-dd HH:mm")}]]});